content.PrologProcedure:
# =============================================
# Build Period Dimension — GBL Period
# Parameters: pFirstFY, pLastFY, pFYStartM, pCurrentPeriod
# =============================================

# ── Input: constant, string working copies ──
cDimension = 'GBL Period';
sCurrentPeriod = pCurrentPeriod;
sMsg = '';
  
# ── Validate parameters ──
nFirstFY = NUMBR(TRIM(pFirstFY));
IF(nFirstFY < 1900 % nFirstFY > 2200);
  sMsg = 'pFirstFY invalid: ' | pFirstFY | ' — expected a 4-digit fiscal year number';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;

nLastFY = NUMBR(TRIM(pLastFY));
IF(nLastFY < nFirstFY);
  sMsg = 'pLastFY invalid: ' | pLastFY | ' — must be >= pFirstFY (' | pFirstFY | ')';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;

nFYStartM = NUMBR(TRIM(pFYStartM));
IF(nFYStartM < 1 % nFYStartM > 12);
  sMsg = 'pFYStartM invalid: ' | pFYStartM | ' — must be 1-12';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;

IF(sCurrentPeriod @= '');
  sMsg = 'pCurrentPeriod is required — format YYYY-MM e.g. 2027-05';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;
IF(LONG(sCurrentPeriod) <> 7 % SUBST(sCurrentPeriod, 5, 1) @<> '-');
  sMsg = 'pCurrentPeriod invalid format: ' | sCurrentPeriod | ' — expected YYYY-MM e.g. 2027-05';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;
nCPYear  = NUMBR(SUBST(sCurrentPeriod, 1, 4));
nCPMonth = NUMBR(SUBST(sCurrentPeriod, 6, 2));
IF(nCPYear < nFirstFY % nCPYear > nLastFY % nCPMonth < 1 % nCPMonth > 12);
  sMsg = 'pCurrentPeriod out of range: ' | sCurrentPeriod | ' — year must be ' | NumberToString(nFirstFY) | '-' | NumberToString(nLastFY) | ', month 1-12';
  AttrPutS(ATTRS('}Processes', GetProcessName(), '__RUN_LOG') | sMsg | CHAR(10), '}Processes', GetProcessName(), '__RUN_LOG');
  ProcessError;
ENDIF;

# 1. Create Dimension
# ─────────────────────────────────────────────
# Create the dimension if it does not already exist
IF(DIMIX('}Dimensions', cDimension) = 0);
    DimensionCreate(cDimension);
ENDIF;

# 2. Create Attributes
# ─────────────────────────────────────────────
# Create element attributes (N = numeric, S = string, A = alias)
sAttrDim = '}ElementAttributes_' | cDimension;
IF(DIMIX(sAttrDim, 'Period Start Serial') = 0); AttrInsert(cDimension, '', 'Period Start Serial', 'N'); ENDIF;
IF(DIMIX(sAttrDim, 'Period End Serial') = 0); AttrInsert(cDimension, '', 'Period End Serial', 'N'); ENDIF;
IF(DIMIX(sAttrDim, 'Calendar Year') = 0); AttrInsert(cDimension, '', 'Calendar Year', 'N'); ENDIF;
IF(DIMIX(sAttrDim, 'Calendar Month') = 0); AttrInsert(cDimension, '', 'Calendar Month', 'N'); ENDIF;
IF(DIMIX(sAttrDim, 'Days in Period') = 0); AttrInsert(cDimension, '', 'Days in Period', 'N'); ENDIF;
IF(DIMIX(sAttrDim, 'Fin Year') = 0); AttrInsert(cDimension, '', 'Fin Year', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'First Period') = 0); AttrInsert(cDimension, '', 'First Period', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Last Period') = 0); AttrInsert(cDimension, '', 'Last Period', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Previous Period') = 0); AttrInsert(cDimension, '', 'Previous Period', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Next Period') = 0); AttrInsert(cDimension, '', 'Next Period', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Caption') = 0); AttrInsert(cDimension, '', 'Caption', 'A'); ENDIF;
IF(DIMIX(sAttrDim, 'Long Name') = 0); AttrInsert(cDimension, '', 'Long Name', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Is Current Period') = 0); AttrInsert(cDimension, '', 'Is Current Period', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'YTD') = 0); AttrInsert(cDimension, '', 'YTD', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'YTG') = 0); AttrInsert(cDimension, '', 'YTG', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'LTD') = 0); AttrInsert(cDimension, '', 'LTD', 'S'); ENDIF;
IF(DIMIX(sAttrDim, 'Period Type') = 0); AttrInsert(cDimension, '', 'Period Type', 'S'); ENDIF;

# Date Formatter
nFmt = NewDateFormatter('yyyyMMdd');

# =============================================
# 3. BUILD STRUCTURE
# =============================================
# Loops through each FY year
# For each FY: creates consolidation, OBL, 12 months
# Then builds YTD/YTG/LTD consolidations with correct child ranges
# ═══════════════════════════════════════════════════════════
nFY = nFirstFY;

WHILE(nFY <= nLastFY);

    IF(nFYStartM = 1);
        nFisStartY = nFY; nFisStartM = 1; nFisEndY = nFY; nFisEndM = 12;
    ELSE;
        nFisStartY = nFY - 1; nFisStartM = nFYStartM; nFisEndY = nFY; nFisEndM = nFYStartM - 1;
    ENDIF;

    # ─────────────────────────────────────────────
    # Create FY consolidation (e.g. FY2025)
    # ─────────────────────────────────────────────
    sFY = 'FY' | NumberToString(nFY);

    IF(DIMIX(cDimension, sFY) = 0);
        DimensionElementInsert(cDimension, '', sFY, 'C');
    ENDIF;

    # ─────────────────────────────────────────────
    # Create OBL leaf (e.g. 2025 OBL)
    # ─────────────────────────────────────────────
    sOBL = NumberToString(nFY) | ' OBL';
    IF(DIMIX(cDimension, sOBL) = 0);
        DimensionElementInsert(cDimension, '', sOBL, 'N');
    ENDIF;

    # ─────────────────────────────────────────────
    # Create 12 months and link to FY
    # ─────────────────────────────────────────────
    nFisY = nFisStartY;
    nFisM = nFisStartM;
    nMonthCount = 0;

    WHILE(nMonthCount < 12);
        sMonth = NumberToString(nFisY) | '-' | IF(nFisM < 10, '0' | NumberToString(nFisM), NumberToString(nFisM));
        IF(DIMIX(cDimension, sMonth) = 0);
            DimensionElementInsert(cDimension, '', sMonth, 'N');
        ENDIF;
        DimensionElementComponentAdd(cDimension, sFY, sMonth, 1);
        nFisM = nFisM + 1;
        IF(nFisM > 12); nFisM = 1; nFisY = nFisY + 1; ENDIF;
        nMonthCount = nMonthCount + 1;
    END;

    # ─────────────────────────────────────────────
    # Build YTD / YTG / LTD per-month consolidations
    # YTD = months from FY start through current; YTG = remaining months
    # LTD = OBL + YTD
    # ─────────────────────────────────────────────
    nPos = 0;
    nCalY = nFisStartY;
    nCalM = nFisStartM;

    WHILE(nPos < 12);
        sYM = NumberToString(nCalY) | '-' | IF(nCalM < 10, '0' | NumberToString(nCalM), NumberToString(nCalM));
        nFisP = MOD(nCalM - nFYStartM + 12, 12) + 1;
        sYTDName = 'YTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sYTGName = 'YTG FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sLTDName = 'LTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));

        DimensionElementInsert(cDimension, '', sYTDName, 'C');
        DimensionElementInsert(cDimension, '', sYTGName, 'C');
        DimensionElementInsert(cDimension, '', sLTDName, 'C');

        # Walk all 12 months and classify as YTD / YTG
        nInner = 0;
        nIY = nFisStartY;
        nIM = nFisStartM;
        WHILE(nInner < 12);
            sIM = NumberToString(nIY) | '-' | IF(nIM < 10, '0' | NumberToString(nIM), NumberToString(nIM));
            IF(nInner <= nPos);
                DimensionElementComponentAdd(cDimension, sYTDName, sIM, 1);
            ENDIF;
            IF(nInner > nPos);
                DimensionElementComponentAdd(cDimension, sYTGName, sIM, 1);
            ENDIF;
            nIM = nIM + 1;
            IF(nIM > 12); nIM = 1; nIY = nIY + 1; ENDIF;
            nInner = nInner + 1;
        END;

        DimensionElementComponentAdd(cDimension, sLTDName, sOBL, 1);
        DimensionElementComponentAdd(cDimension, sLTDName, sYTDName, 1);

        nCalM = nCalM + 1;
        IF(nCalM > 12); nCalM = 1; nCalY = nCalY + 1; ENDIF;
        nPos = nPos + 1;
    END;

    nFY = nFY + 1;
END;

# =============================================
# Top-Level Consolidations
# Populates All Periods, All FY, All YTD, All YTG, All LTD, All OBL
# =============================================
IF(DIMIX(cDimension, 'All Periods') = 0); DimensionElementInsert(cDimension, '', 'All Periods', 'C'); ENDIF;
IF(DIMIX(cDimension, 'All FY') = 0);  DimensionElementInsert(cDimension, '', 'All FY', 'C'); ENDIF;
IF(DIMIX(cDimension, 'All YTD') = 0); DimensionElementInsert(cDimension, '', 'All YTD', 'C'); ENDIF;
IF(DIMIX(cDimension, 'All YTG') = 0); DimensionElementInsert(cDimension, '', 'All YTG', 'C'); ENDIF;
IF(DIMIX(cDimension, 'All LTD') = 0); DimensionElementInsert(cDimension, '', 'All LTD', 'C'); ENDIF;
IF(DIMIX(cDimension, 'All OBL') = 0); DimensionElementInsert(cDimension, '', 'All OBL', 'C'); ENDIF;
IF(DIMIX(cDimension, 'Rolling 12') = 0); DimensionElementInsert(cDimension, '', 'Rolling 12', 'C'); ENDIF;
IF(DIMIX(cDimension, 'Rolling 6') = 0); DimensionElementInsert(cDimension, '', 'Rolling 6', 'C'); ENDIF;
IF(DIMIX(cDimension, 'Rolling 3') = 0); DimensionElementInsert(cDimension, '', 'Rolling 3', 'C'); ENDIF;

nFY = nFirstFY;
WHILE(nFY <= nLastFY);
    IF(nFYStartM = 1);
        nFisStartY = nFY; nFisStartM = 1;
    ELSE;
        nFisStartY = nFY - 1; nFisStartM = nFYStartM;
    ENDIF;
    sFY = 'FY' | NumberToString(nFY);
    sOBL = NumberToString(nFY) | ' OBL';

    IF(DIMIX(cDimension, sFY) > 0);
        DimensionElementComponentAdd(cDimension, 'All FY', sFY, 1);
    ENDIF;
    IF(DIMIX(cDimension, sOBL) > 0);
        DimensionElementComponentAdd(cDimension, 'All OBL', sOBL, 1);
    ENDIF;

    nCY = nFisStartY; nCM = nFisStartM; nCount = 0;
    WHILE(nCount < 12);
        sM = NumberToString(nCY) | '-' | IF(nCM < 10, '0' | NumberToString(nCM), NumberToString(nCM));
        nFisP = MOD(nCM - nFYStartM + 12, 12) + 1;
        DimensionElementComponentAdd(cDimension, 'All Periods', sM, 1);
        sYTDName = 'YTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sYTGName = 'YTG FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sLTDName = 'LTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        IF(DIMIX(cDimension, sYTDName) > 0); DimensionElementComponentAdd(cDimension, 'All YTD', sYTDName, 1); ENDIF;
        IF(DIMIX(cDimension, sYTGName) > 0); DimensionElementComponentAdd(cDimension, 'All YTG', sYTGName, 1); ENDIF;
        IF(DIMIX(cDimension, sLTDName) > 0); DimensionElementComponentAdd(cDimension, 'All LTD', sLTDName, 1); ENDIF;
        nCM = nCM + 1; IF(nCM > 12); nCM = 1; nCY = nCY + 1; ENDIF;
        nCount = nCount + 1;
    END;

    nFY = nFY + 1;
END;

content.EpilogProcedure:
# =============================================
# 4. WRITE ATTRIBUTES
# =============================================
nFY = nFirstFY;

WHILE(nFY <= nLastFY);

    IF(nFYStartM = 1);
        nFisStartY = nFY; nFisStartM = 1; nFisEndY = nFY; nFisEndM = 12;
    ELSE;
        nFisStartY = nFY - 1; nFisStartM = nFYStartM; nFisEndY = nFY; nFisEndM = nFYStartM - 1;
    ENDIF;

    sFY = 'FY' | NumberToString(nFY);
    sOBL = NumberToString(nFY) | ' OBL';

    IF(DIMIX(cDimension, sOBL) > 0);
        ElementAttrPutS(sFY, cDimension, '', sOBL, 'Fin Year');
        ElementAttrPutS('OBL', cDimension, '', sOBL, 'Period Type');
        ElementAttrPutS(sOBL, cDimension, '', sOBL, 'Caption');
        ElementAttrPutS('Opening Balance ' | NumberToString(nFY), cDimension, '', sOBL, 'Long Name');
    ENDIF;

    nFisY = nFisStartY;
    nFisM = nFisStartM;
    nMonthCount = 0;

    WHILE(nMonthCount < 12);
       
        sMonth = NumberToString(nFisY) | '-' | IF(nFisM < 10, '0' | NumberToString(nFisM), NumberToString(nFisM));

        IF(DIMIX(cDimension, sMonth) > 0);
            nYear = nFisY;
            nMonth = nFisM;

            IF(nMonth = 2);
                nDays = 28;
            ELSEIF(nMonth = 4 % nMonth = 6 % nMonth = 9 % nMonth = 11);
                nDays = 30;
            ELSE;
                nDays = 31;
            ENDIF;

            IF(nFisM = 1);
                nPrevY = nFisY - 1; nPrevM = 12;
            ELSE;
                nPrevY = nFisY; nPrevM = nFisM - 1;
            ENDIF;

            IF(nFisM = 12);
                nNextY = nFisY + 1; nNextM = 1;
            ELSE;
                nNextY = nFisY; nNextM = nFisM + 1;
            ENDIF;

            sPrev   = NumberToString(nPrevY) | '-' | IF(nPrevM < 10, '0' | NumberToString(nPrevM), NumberToString(nPrevM));
            sNext   = NumberToString(nNextY) | '-' | IF(nNextM < 10, '0' | NumberToString(nNextM), NumberToString(nNextM));
            sFirstM = NumberToString(nFisStartY) | '-' | IF(nFisStartM < 10, '0' | NumberToString(nFisStartM), NumberToString(nFisStartM));
            sLastM  = NumberToString(nFisEndY) | '-' | IF(nFisEndM < 10, '0' | NumberToString(nFisEndM), NumberToString(nFisEndM));

            nFisP = MOD(nFisM - nFYStartM + 12, 12) + 1;
            sYTD = 'YTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
            sYTG = 'YTG FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
            sLTD = 'LTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));

            sStartStr = NumberToString(nYear) | IF(nMonth < 10, '0', '') | NumberToString(nMonth) | '01';
            sEndStr   = NumberToString(nYear) | IF(nMonth < 10, '0', '') | NumberToString(nMonth) | IF(nDays < 10, '0', '') | NumberToString(nDays);
            nStartSerial = ParseDate(sStartStr, 'yyyyMMdd', nFmt) + 21916;
            nEndSerial   = ParseDate(sEndStr,   'yyyyMMdd', nFmt) + 21916;

            sCaption  = IF(nFisM=1,'Jan',IF(nFisM=2,'Feb',IF(nFisM=3,'Mar',IF(nFisM=4,'Apr',IF(nFisM=5,'May',IF(nFisM=6,'Jun',IF(nFisM=7,'Jul',IF(nFisM=8,'Aug',IF(nFisM=9,'Sep',IF(nFisM=10,'Oct',IF(nFisM=11,'Nov','Dec'))))))))))) | ' ' | SUBST(NumberToString(nYear), 3, 2);
            ElementAttrPutS(sCaption, cDimension, '', sMonth, 'Caption');
            ElementAttrPutS(sMonth, cDimension, '', sMonth, 'Long Name');
            ElementAttrPutS('Month', cDimension, '', sMonth, 'Period Type');
            IF(sMonth @= sCurrentPeriod);
                ElementAttrPutS('Y', cDimension, '', sMonth, 'Is Current Period');
            ELSE;
                ElementAttrPutS('', cDimension, '', sMonth, 'Is Current Period');
            ENDIF;
            ElementAttrPutN(nStartSerial, cDimension, '', sMonth, 'Period Start Serial');
            ElementAttrPutN(nEndSerial,   cDimension, '', sMonth, 'Period End Serial');
            ElementAttrPutN(nYear,        cDimension, '', sMonth, 'Calendar Year');
            ElementAttrPutN(nMonth,       cDimension, '', sMonth, 'Calendar Month');
            ElementAttrPutN(nDays,        cDimension, '', sMonth, 'Days in Period');
            ElementAttrPutS(sFY,      cDimension, '', sMonth, 'Fin Year');
            ElementAttrPutS(sFirstM,  cDimension, '', sMonth, 'First Period');
            ElementAttrPutS(sLastM,   cDimension, '', sMonth, 'Last Period');
            ElementAttrPutS(sPrev,    cDimension, '', sMonth, 'Previous Period');
            ElementAttrPutS(sNext,    cDimension, '', sMonth, 'Next Period');
            ElementAttrPutS(sYTD,     cDimension, '', sMonth, 'YTD');
            ElementAttrPutS(sYTG,     cDimension, '', sMonth, 'YTG');
            ElementAttrPutS(sLTD,     cDimension, '', sMonth, 'LTD');
        ENDIF;

        nFisM = nFisM + 1;
        IF(nFisM > 12);
            nFisM = 1;
            nFisY = nFisY + 1;
        ENDIF;
       
        nMonthCount = nMonthCount + 1;
    END;

    nFY = nFY + 1;
END;

# Consolidation Captions
nFY = nFirstFY;
WHILE(nFY <= nLastFY);
    IF(nFYStartM = 1);
        nFisStartY = nFY; nFisStartM = 1;
    ELSE;
        nFisStartY = nFY - 1; nFisStartM = nFYStartM;
    ENDIF;
    nCY = nFisStartY;
    nCM = nFisStartM;
    nCount = 0;
    WHILE(nCount < 12);
        nFisP = MOD(nCM - nFYStartM + 12, 12) + 1;
        sYTDName = 'YTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sYTGName = 'YTG FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sLTDName = 'LTD FY' | NumberToString(nFY) | ' P' | IF(nFisP < 10, '0' | NumberToString(nFisP), NumberToString(nFisP));
        sCap = NumberToString(nCY) | '-' | IF(nCM < 10, '0' | NumberToString(nCM), NumberToString(nCM));
        ElementAttrPutS('YTD ' | sCap, cDimension, '', sYTDName, 'Caption');
        ElementAttrPutS('YTG ' | sCap, cDimension, '', sYTGName, 'Caption');
        ElementAttrPutS('LTD ' | sCap, cDimension, '', sLTDName, 'Caption');
        nCM = nCM + 1; IF(nCM > 12); nCM = 1; nCY = nCY + 1; ENDIF;
        nCount = nCount + 1;
    END;
    nFY = nFY + 1;
END;

# =============================================
# 5. POPULATE ROLLING CONSOLIDATIONS (using Next Period chain)
# =============================================
IF(sCurrentPeriod @<> '');
    IF(DIMIX(cDimension, 'Rolling 3') > 0);
        sM = sCurrentPeriod;
        nDone = 0;
        WHILE(nDone < 3 & DIMIX(cDimension, sM) > 0);
            DimensionElementComponentAddDirect(cDimension, 'Rolling 3', sM, 1);
            sM = ATTRS(cDimension, sM, 'Next Period');
            nDone = nDone + 1;
        END;
    ENDIF;
    IF(DIMIX(cDimension, 'Rolling 6') > 0);
        sM = sCurrentPeriod;
        nDone = 0;
        WHILE(nDone < 6 & DIMIX(cDimension, sM) > 0);
            DimensionElementComponentAddDirect(cDimension, 'Rolling 6', sM, 1);
            sM = ATTRS(cDimension, sM, 'Next Period');
            nDone = nDone + 1;
        END;
    ENDIF;
    IF(DIMIX(cDimension, 'Rolling 12') > 0);
        sM = sCurrentPeriod;
        nDone = 0;
        WHILE(nDone < 12 & DIMIX(cDimension, sM) > 0);
            DimensionElementComponentAddDirect(cDimension, 'Rolling 12', sM, 1);
            sM = ATTRS(cDimension, sM, 'Next Period');
            nDone = nDone + 1;
        END;
    ENDIF;
ENDIF;
